mapper.select:
SELECT /* base.sy :: SyI18nMsg :: selectList */ m.* , cd_lc.code_label AS lang_cd_nm FROM sy_i18n_msg m LEFT JOIN sy_code cd_lc ON cd_lc.code_grp = 'LANG_CODE' AND cd_lc.code_value = m.lang_cd
ORDER BY m.i18n_msg_id ASC ORDER BY m.i18n_msg_id DESC ORDER BY m.reg_date ASC ORDER BY m.reg_date DESC ORDER BY m.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.sy :: SyI18nMsg :: selectPageList */ m.* , cd_lc.code_label AS lang_cd_nm FROM sy_i18n_msg m LEFT JOIN sy_code cd_lc ON cd_lc.code_grp = 'LANG_CODE' AND cd_lc.code_value = m.lang_cd
ORDER BY m.i18n_msg_id ASC ORDER BY m.i18n_msg_id DESC ORDER BY m.reg_date ASC ORDER BY m.reg_date DESC ORDER BY m.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

