UPDATE sy_i18n_msg /* base.sy :: SyI18nMsg :: updateSelective */
i18n_id = #{i18nId}, lang_cd = #{langCd}, i18n_msg = #{i18nMsg}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE i18n_msg_id = #{i18nMsgId}
